unit lipdecide;

{ Launch Interceptor Program - DECIDE and REALCOMPARE (Knight & Leveson) }

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

{ ---------------------------------------------------------------------------
  REALCOMPARE: compare reals using six most significant figures.
  ------------------------------------------------------------------------- }

function REALCOMPARE(A, B: real): COMPTYPE;
const
  LN10: real   = 2.302585093;
  MNZ:  real  = 1E-99;
var
  sa, sb:     integer;
  aabs, babs: real;
  m, e, sc:  real;
  na, nb:     int64;
begin
  if A < 0 then
    sa := -1
  else if A > 0 then
    sa := 1
  else
    sa := 0;
  if B < 0 then
    sb := -1
  else if B > 0 then
    sb := 1
  else
    sb := 0;
  aabs := abs(A);
  babs := abs(B);

  if (sa = 0) and (sb = 0) then
  begin
    REALCOMPARE := EQ;
    exit;
  end
  else if (sa = 0) and (sb <> 0) then
  begin
    if babs < MNZ then
      REALCOMPARE := EQ
    else
      REALCOMPARE := LT;
    exit;
  end
  else if (sa <> 0) and (sb = 0) then
  begin
    if aabs < MNZ then
      REALCOMPARE := EQ
    else
      REALCOMPARE := GT;
    exit;
  end
  else if sa < sb then
  begin
    REALCOMPARE := LT;
    exit;
  end
  else if sa > sb then
  begin
    REALCOMPARE := GT;
    exit;
  end;

  if aabs < babs then
    m := babs
  else
    m := aabs;
  if m < MNZ then
  begin
    REALCOMPARE := EQ;
    exit;
  end;
  e := floor(ln(m) / LN10);
  sc := exp(ln(10) * (5.0 - e));
  na := Trunc(0.5 + aabs * sc);
  nb := Trunc(0.5 + babs * sc);
  if na = nb then
  begin
    if sa = -1 then
    begin
      if aabs > babs then
        REALCOMPARE := LT
      else if aabs < babs then
        REALCOMPARE := GT
      else
        REALCOMPARE := EQ;
    end
    else
    begin
      if aabs < babs then
        REALCOMPARE := LT
      else if aabs > babs then
        REALCOMPARE := GT
      else
        REALCOMPARE := EQ;
    end;
    exit;
  end
  else if na < nb then
  begin
    if sa = -1 then
      REALCOMPARE := GT
    else
      REALCOMPARE := LT;
  end
  else
  begin
    if sa = -1 then
      REALCOMPARE := LT
    else
      REALCOMPARE := GT;
  end;
end;

{ ------------------------------------------------------------------------- }

function R_Lt(const A, B: real): boolean; inline;
begin
  R_Lt := REALCOMPARE(A, B) = LT;
end;

function R_Le(const A, B: real): boolean; inline;
var
  c: COMPTYPE;
begin
  c  := REALCOMPARE(A, B);
  R_Le := (c = LT) or (c = EQ);
end;

function R_Gt(const A, B: real): boolean; inline;
begin
  R_Gt := REALCOMPARE(A, B) = GT;
end;

function R_Ge(const A, B: real): boolean; inline;
var
  c: COMPTYPE;
begin
  c  := REALCOMPARE(A, B);
  R_Ge := (c = GT) or (c = EQ);
end;

function R_Eq(const A, B: real): boolean; inline;
begin
  R_Eq := REALCOMPARE(A, B) = EQ;
end;

function Dist2(x1, y1, x2, y2: real): real; inline;
begin
  Dist2 := sqr(x2 - x1) + sqr(y2 - y1);
end;

function DistP(x1, y1, x2, y2: real): real;
begin
  DistP := sqrt(Dist2(x1, y1, x2, y2));
end;

function CrossTwice(x1, y1, x2, y2, x3, y3: real): real; inline;
begin
  CrossTwice := (x2 - x1) * (y3 - y1) - (y2 - y1) * (x3 - x1);
end;

function MinEnclosingR3(x1, y1, x2, y2, x3, y3: real): real;
var
  d12, d23, d31, tw, A, t1, t2, t3, Rmx:     real;
  m12, m23, m31:  boolean;
  colin, obt, br: boolean;
  circ, mx:       real;
begin
  d12 := DistP(x1, y1, x2, y2);
  d23 := DistP(x2, y2, x3, y3);
  d31 := DistP(x3, y3, x1, y1);
  tw  := abs(CrossTwice(x1, y1, x2, y2, x3, y3));
  A   := 0.5 * tw;
  colin := (REALCOMPARE(A, 0) = EQ);

  if colin then
  begin
    if R_Ge(d12, d23) and R_Ge(d12, d31) then
      mx := d12
    else if R_Ge(d23, d12) and R_Ge(d23, d31) then
      mx := d23
    else
      mx := d31;
    MinEnclosingR3 := 0.5 * mx;
    exit;
  end;

  t1  := sqr(d12);
  t2  := sqr(d23);
  t3  := sqr(d31);
  m12 := R_Ge(t1, t2) and R_Ge(t1, t3);
  m23 := R_Ge(t2, t1) and R_Ge(t2, t3);
  m31 := R_Ge(t3, t1) and R_Ge(t3, t2);
  obt := false;
  if m12 then
    br := R_Ge(t1, t2 + t3)
  else
    br := false;
  obt := obt or br;
  if m23 then
    br := R_Ge(t2, t1 + t3)
  else
    br := false;
  obt := obt or br;
  if m31 then
    br := R_Ge(t3, t1 + t2)
  else
    br := false;
  obt := obt or br;

  if R_Ge(d12, d23) and R_Ge(d12, d31) then
    Rmx := d12
  else if R_Ge(d23, d12) and R_Ge(d23, d31) then
    Rmx := d23
  else
    Rmx := d31;

  if obt then
    MinEnclosingR3 := 0.5 * Rmx
  else
  begin
    circ := (d12 * d23 * d31) / (4.0 * A);
    MinEnclosingR3 := circ;
  end;
end;

{ Quadrant per spec (priority: I in ambiguous cases). }
function Quadrant(px, py: real): integer;
begin
  if R_Eq(px, 0) and R_Eq(py, 0) then
    Quadrant := 1
  else if R_Lt(px, 0) and R_Lt(py, 0) then
    Quadrant := 3
  else if R_Lt(px, 0) and R_Ge(py, 0) then
    Quadrant := 2
  else if R_Eq(px, 0) and R_Lt(py, 0) then
    Quadrant := 3
  else if R_Eq(px, 0) and R_Gt(py, 0) then
    Quadrant := 1
  else if R_Gt(px, 0) and R_Eq(py, 0) then
    Quadrant := 1
  else if R_Gt(px, 0) and R_Gt(py, 0) then
    Quadrant := 1
  else if R_Gt(px, 0) and R_Lt(py, 0) then
    Quadrant := 4
  else
    Quadrant := 2;
end;

{ Angle at vertex: vectors vx,vy and wx,wy; interior angle a in (0, pi). }
function InteriorAngleValid(vx, vy, wx, wy: real; eps: real): boolean;
var
  lenu, lenw, t, a:     real;
begin
  lenu := sqrt(sqr(vx) + sqr(vy));
  lenw := sqrt(sqr(wx) + sqr(wy));
  if (REALCOMPARE(lenu, 0) = EQ) or (REALCOMPARE(lenw, 0) = EQ) then
  begin
    InteriorAngleValid := false;
    exit;
  end;
  t := (vx * wx + vy * wy) / (lenu * lenw);
  if R_Lt(t, -1) then
    t := -1
  else if R_Gt(t, 1) then
    t   := 1;
  a := arccos(t);
  { not nearly collinear: avoid angle ~ 0 and ~ pi }
  InteriorAngleValid := R_Gt(a, eps) and R_Lt(a, PI - eps);
end;

{ Distance from p to line through a..b. If a=b, return distance p-a. }
function LineDist(ax, ay, bx, by, px, py: real): real;
var
  vx, vy, wx, wy, c, len: real;
begin
  vx  := bx - ax;
  vy  := by - ay;
  wx  := px - ax;
  wy  := py - ay;
  len := sqrt(sqr(vx) + sqr(vy));
  if (REALCOMPARE(len, 0) = EQ) then
    LineDist := DistP(ax, ay, px, py)
  else
  begin
    c := abs(vx * wy - vy * wx);
    LineDist := c / len;
  end;
end;

procedure EvalCMV;
var
  i, j, s, c, p2, p3, q, cnt, h: integer;
  b1, b2:  boolean;
  d, L1, L2:  real;
  inwin:  array[1..4] of boolean;
  nq, k:  integer;
  x1, y1, x2, y2:  real;
  R, ar:  real;
begin
  { 1: consecutive length > L1 }
  b1    := false;
  L1    := PARAMETERS.Length1;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := DistP(X[i], Y[i], X[i + 1], Y[i + 1]);
    if R_Gt(d, L1) then
    begin
      b1  := true;
      break;
    end;
  end;
  CMV[1] := b1;

  { 2: three consecutive not in circle r<=R1 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      R  := MinEnclosingR3(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
      b1 := b1 or R_Gt(R, PARAMETERS.Radius1);
    end;
  end;
  CMV[2] := b1;

  { 3: angle at i+1: points i, i+1, i+2 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      x1 := X[i] - X[i + 1];
      y1 := Y[i] - Y[i + 1];
      x2 := X[i + 2] - X[i + 1];
      y2 := Y[i + 2] - Y[i + 1];
      if InteriorAngleValid(x1, y1, x2, y2, PARAMETERS.Epsilon) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[3] := b1;

  { 4: triangle area (three consecutive) > A1 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      ar  := 0.5 * abs(
        (X[i + 1] - X[i]) * (Y[i + 2] - Y[i]) -
        (X[i + 2] - X[i]) * (Y[i + 1] - Y[i]));
      if R_Gt(ar, PARAMETERS.Area1) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[4] := b1;

  { 5: Q_PTS in a row in more than QUADS quadrants }
  b1 := false;
  q  := PARAMETERS.Q_PTS;
  c  := PARAMETERS.Quads;
  for s := 1 to NUMPOINTS - q + 1 do
  begin
    for h := 1 to 4 do
      inwin[h]  := false;
    for j := 0 to q - 1 do
    begin
      k  := s + j;
      cnt := Quadrant(X[k], Y[k]);
      inwin[cnt]  := true;
    end;
    nq  := 0;
    for h := 1 to 4 do
      if inwin[h] then
        Inc(nq);
    if nq > c then
    begin
      b1  := true;
      break;
    end;
  end;
  CMV[5] := b1;

  { 6: consecutive X decreasing }
  b1 := false;
  for i := 1 to NUMPOINTS - 1 do
    if R_Lt(X[i + 1] - X[i], 0) then
    begin
      b1  := true;
      break;
    end;
  CMV[6] := b1;

  { 7: N_PTS window, one point far from line f-l }
  b1 := false;
  if (NUMPOINTS >= 3) and (Parameters.N_Pts <= NUMPOINTS) then
  begin
    for s := 1 to NUMPOINTS - Parameters.N_Pts + 1 do
    begin
      x1 := X[s];
      y1 := Y[s];
      x2 := X[s + Parameters.N_Pts - 1];
      y2 := Y[s + Parameters.N_Pts - 1];
      for j := 1 to Parameters.N_Pts - 2 do
      begin
        c := s + j;
        d := LineDist(x1, y1, x2, y2, X[c], Y[c]);
        if R_Gt(d, PARAMETERS.Dist) then
        begin
          b1  := true;
          break;
        end;
      end;
      if b1 then
        break;
    end;
  end;
  CMV[7] := b1;

  { 8: (i, i+K+1) distance > L1 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    c := Parameters.K_Pts;
    for i := 1 to NUMPOINTS - c - 1 do
    begin
      p2  := i + c + 1;
      d   := DistP(X[i], Y[i], X[p2], Y[p2]);
      if R_Gt(d, L1) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[8] := b1;

  { 9: A_PTS, B_PTS separation; circum > R1 }
  b1 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - Parameters.A_Pts - Parameters.B_Pts - 2 do
    begin
      p2  := s + Parameters.A_Pts + 1;
      p3  := p2 + Parameters.B_Pts + 1;
      R   := MinEnclosingR3(
        X[s], Y[s], X[p2], Y[p2], X[p3], Y[p3]);
      if R_Gt(R, PARAMETERS.Radius1) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[9] := b1;

  { 10: C_PTS, D_PTS, angle at middle }
  b1 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - Parameters.C_Pts - Parameters.D_Pts - 2 do
    begin
      p2  := s + Parameters.C_Pts + 1;
      p3  := p2 + Parameters.D_Pts + 1;
      x1  := X[s] - X[p2];
      y1  := Y[s] - Y[p2];
      x2  := X[p3] - X[p2];
      y2  := Y[p3] - Y[p2];
      if InteriorAngleValid(x1, y1, x2, y2, PARAMETERS.Epsilon) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[10] := b1;

  { 11: E_PTS, F_PTS, area }
  b1 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - Parameters.E_Pts - Parameters.F_Pts - 2 do
    begin
      p2  := s + Parameters.E_Pts + 1;
      p3  := p2 + Parameters.F_Pts + 1;
      ar  := 0.5 * abs(
        (X[p2] - X[s]) * (Y[p3] - Y[s]) -
        (X[p3] - X[s]) * (Y[p2] - Y[s]));
      if R_Gt(ar, PARAMETERS.Area1) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[11] := b1;

  { 12: G_PTS, X[j]-X[i] < 0 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    c := Parameters.G_Pts;
    for i := 1 to NUMPOINTS - c - 1 do
    begin
      p2  := i + c + 1;
      if R_Lt(X[p2] - X[i], 0) then
      begin
        b1  := true;
        break;
      end;
    end;
  end;
  CMV[12] := b1;

  { 13: K_PTS, >L1 and <L2 (strict) }
  b1   := false;
  L2  := Parameters.Length2;
  if NUMPOINTS >= 3 then
  begin
    c := Parameters.K_Pts;
    b2 := false;
    for i := 1 to NUMPOINTS - c - 1 do
    begin
      p2  := i + c + 1;
      d   := DistP(X[i], Y[i], X[p2], Y[p2]);
      if (not b1) and R_Gt(d, L1) then
        b1  := true;
      if (not b2) and R_Lt(d, L2) then
        b2  := true;
      if b1 and b2 then
        break;
    end;
  end
  else
  begin
    b1  := false;
    b2  := false;
  end;
  CMV[13]  := b1 and b2;

  { 14: A/B gaps, R>R1 and R<=R2 }
  b1 := false;
  b2 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - Parameters.A_Pts - Parameters.B_Pts - 2 do
    begin
      p2  := s + Parameters.A_Pts + 1;
      p3  := p2 + Parameters.B_Pts + 1;
      R   := MinEnclosingR3(
        X[s], Y[s], X[p2], Y[p2], X[p3], Y[p3]);
      if (not b1) and R_Gt(R, PARAMETERS.Radius1) then
        b1  := true;
      if (not b2) and R_Le(R, PARAMETERS.Radius2) then
        b2  := true;
      if b1 and b2 then
        break;
    end;
  end;
  CMV[14]  := b1 and b2;

  { 15: E_F gaps, area >A1 and <A2 }
  b1 := false;
  b2 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - Parameters.E_Pts - Parameters.F_Pts - 2 do
    begin
      p2  := s + Parameters.E_Pts + 1;
      p3  := p2 + Parameters.F_Pts + 1;
      ar  := 0.5 * abs(
        (X[p2] - X[s]) * (Y[p3] - Y[s]) -
        (X[p3] - X[s]) * (Y[p2] - Y[s]));
      if (not b1) and R_Gt(ar, PARAMETERS.Area1) then
        b1  := true;
      if (not b2) and R_Lt(ar, PARAMETERS.Area2) then
        b2  := true;
      if b1 and b2 then
        break;
    end;
  end;
  CMV[15]  := b1 and b2;
end;

procedure DECIDE;
var
  i, j:  integer;
  row: boolean;
  all: boolean;
  op:  CONNECTORS;
  ci, cj: boolean;
begin
  EvalCMV;

  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
      begin
        op  := LCM[i, j];
        ci  := CMV[i];
        cj  := CMV[j];
        if op = NOTUSED then
          PUM[i, j]  := true
        else if op = ANDD then
          PUM[i, j]  := ci and cj
        else { ORR }
          PUM[i, j]  := ci or cj;
      end;

  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i]  := true
    else
    begin
      row  := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          row  := false;
          break;
        end;
      FUV[i]  := row;
    end;
  end;

  all  := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      all  := false;
      break;
    end;
  LAUNCH  := all;
end;

end.
